local TD = TD.td1madao["ydj_dst_td1madao"] TD.createFn("blewUp", function(v, player)     if not TD.valid(v) then         return     end     if v and v.sg and not v.components.health:IsDead() then         if v.brain and v.brain.Stop then             v.brain:Stop()         end         if v:HasTag("player") then             if v.components.playercontroller then                 v.components.playercontroller:Enable(false)             end         end         local x2, y2, z2 = TD.pos(v)         local sign = 1         TD.period(v, nil, function()             local x3, y3, z3 = TD.pos(v)             if TD.valid(v) then                 v.Transform:SetPosition(x2, y3 + 0.7 * sign, z2)             end         end, 0.05, 0.6, function()             if TD.valid(v) then                 v.Transform:SetPosition(x2, 0, z2)             end         end)         v:DoTaskInTime(0.3, function()             sign = -1         end)         if v and v.components and v.components.combat and v.components.combat.BlankOutAttacks and v.replica and v.replica.combat and v.replica.combat.SetCanAttack then             if TD.valid(v) then                 v.components.combat:BlankOutAttacks(1)             end         end         if v.sg and v.sg.sg and v.sg.sg.states and v.sg.sg.states.hit and not v.components.health:IsDead() then             TD.goto(v, "hit")         end         v:DoTaskInTime(1, function()             if not TD.valid(v) then                 return             end             if v and v.brain and v.brain.Start then                 v.brain:Start()             end             if v and v.HasTag and v:HasTag("player") then                 if v.components and v.components.playercontroller and v.components.playercontroller.Enable then                     v.components.playercontroller:Enable(true)                 end             end         end)         v:DoTaskInTime(1.5, function()             if not (TD.valid(v)) then                 return             end             if v and v.components and v.components.combat and v.replica and v.replica.combat and not v:HasTag("player") then                 TD.prefabTarget(v, (player or TD.GetPlayer()))             end             local time = GetTime()             if v and v.components and v.components.combat and v.replica and v.replica.combat and v.components.combat.min_attack_period > 1.5 then                 time = time - v.components.combat.min_attack_period + 1.5             end             if v and v.components and v.components.combat and v.replica and v.replica.combat then                 v.components.combat.laststartattacktime = time             end         end)     end end) TD.createFn("fly", function(inst, world)     if not inst then         inst = TD.GetPlayer()     end     inst.Physics:ClearMotorVelOverride()     inst.Physics:SetCollisionGroup(COLLISION.CHARACTERS)     inst.Physics:ClearCollisionMask()     inst.Physics:CollidesWith(COLLISION.GROUND)     if world then         inst.Physics:CollidesWith(COLLISION.WORLD)     end end) TD.createFn("stopFly", function(inst)     if not inst then         inst = TD.GetPlayer()     end     inst.Physics:ClearMotorVelOverride()     inst.Physics:SetCollisionGroup(COLLISION.CHARACTERS)     inst.Physics:ClearCollisionMask()     inst.Physics:CollidesWith(COLLISION.WORLD)     inst.Physics:CollidesWith(COLLISION.OBSTACLES)     inst.Physics:CollidesWith(COLLISION.CHARACTERS)     inst.Physics:CollidesWith(COLLISION.ITEMS)     inst.Physics:CollidesWith(COLLISION.GROUND) end) TD.createFn("deepFrozen", function(v, player)     if v and v.sg and v.sg.sg and v.sg.sg.states and v.sg.sg.states.frozen and not v.components.health:IsDead() and v.components.freezable then         local dizztTime = 5         if v.brain then             v.brain:Stop()         end         if v:HasTag("player") then             if v.components.playercontroller then                 v.components.playercontroller:Enable(false)             end         end         if v.components.locomotor then             v.components.locomotor:Stop()         end         TD.period(v, nil, function()             if not v.components.freezable:IsFrozen() then                 v.components.freezable:Freeze(dizztTime)             end         end, 0.1, dizztTime)         v:DoTaskInTime(dizztTime, function()             if v.components.freezable:IsFrozen() then                 v.components.freezable:Unfreeze()             end             if v.brain then                 v.brain:Start()                 if v.components.combat and not v:HasTag("player") then                     TD.prefabTarget(v, (player or TD.GetPlayer()))                 end                 local time = GetTime()                 if v.components.combat.min_attack_period > 1.5 then                     time = time - v.components.combat.min_attack_period + 1.5                 end                 v.components.combat.laststartattacktime = time             end             if v:HasTag("player") then                 if v.components.playercontroller then                     v.components.playercontroller:Enable(true)                 end             end             TD.goto(v, "idle")         end)     end end) TD.createFn("regen", function(v, blood, who)     if not who then         who = TD.randomPlayer()     end     if TD.live(v) and TD.isNum(blood) and v.components.health and v.components.combat and TD.isPos(v.components.combat.defaultdamage) then         TD.getC(v, "health", function(comp)             if comp.currenthealth ~= comp.maxhealth then                 comp:DoDelta(blood, false, who.prefab, true, who, true)             end         end)     end end) TD.createFn("dizzy", function(v, player, dizzyEffect, dzt)     if v and v.sg and not v.components.health:IsDead() then         local dizztTime = dzt or 3         if v.brain then             v.brain:Stop()         end         if v:HasTag("player") then             if v.components.playercontroller then                 v.components.playercontroller:Enable(false)             end         end         if v.components.locomotor then             v.components.locomotor:Stop()         end         local dizzy = TD.child(v, dizzyEffect or TD.holder("%s_dizzy_fx"))         dizzy.Transform:SetPosition(0, 1.5, 0)         dizzy:clear(dizztTime)         v:DoTaskInTime(dizztTime, function()             if v.brain then                 v.brain:Start()                 if v.components.combat and not v:HasTag("player") then                     TD.prefabTarget(v, (player or TD.GetPlayer()))                 end                 local time = GetTime()                 if v.components.combat.min_attack_period > 1.5 then                     time = time - v.components.combat.min_attack_period + 1.5                 end                 v.components.combat.laststartattacktime = time             end             if v:HasTag("player") then                 if v.components.playercontroller then                     v.components.playercontroller:Enable(true)                 end             end         end)     end end) local function killFireFx(target)     if target and target.components.burnable and target.components.burnable.KillFX then         target.components.burnable:KillFX()     end     if target.td1madaoGlobalfirefxtask then         target.td1madaoGlobalfirefxtask:Cancel()         target.td1madaoGlobalfirefxtask = nil     end end TD.createFn("fireEffect", function(target)     if target then         killFireFx(target)         if target.components.burnable and target.components.burnable.SpawnFX then             target.components.burnable:SpawnFX(true)         end         target.td1madaoGlobalfirefxtask = target:DoTaskInTime(1, killFireFx)     end end) TD.createFn("dizzy2", function(v, player, dzt)     if v and v.sg and not v.components.health:IsDead() then         local dizztTime = dzt or 1         if v.brain then             v.brain:Stop()         end         if v:HasTag("player") then             if v.components.playercontroller then                 v.components.playercontroller:Enable(false)             end         end         if v.components.locomotor then             v.components.locomotor:Stop()         end         v:DoTaskInTime(dizztTime, function()             if v.brain then                 v.brain:Start()                 if v.components.combat and not v:HasTag("player") then                     TD.prefabTarget(v, (player or TD.GetPlayer()))                 end                 local time = GetTime()                 if v.components.combat.min_attack_period > 1.5 then                     time = time - v.components.combat.min_attack_period + 1.5                 end                 v.components.combat.laststartattacktime = time             end             if v:HasTag("player") then                 if v.components.playercontroller then                     v.components.playercontroller:Enable(true)                 end             end         end)     end end) 